#!/usr/bin/env node

/**
 * Generate device-framed showcase images from raw E2E screenshots.
 *
 * Wraps each screenshot in a macOS-style window frame (title bar with
 * traffic-light buttons, rounded corners, subtle shadow) to produce
 * marketing-quality images for the README gallery.
 *
 * Usage:
 *   pnpm e2e:showcase
 *
 * Prerequisites:
 *   - Raw screenshots must exist in website/docs/public/screenshots/
 *     (generated by pnpm e2e:screenshots:local or pnpm compose:e2e:screenshots)
 *   - Playwright browsers installed (npx playwright install chromium)
 *
 * Output:
 *   website/docs/public/readme/showcase/*.png
 */

import { execSync } from 'node:child_process'

console.log('Generating device-framed showcase images...\n')

try {
  execSync('npx playwright test -c playwright.showcase.config.ts', {
    stdio: 'inherit',
    cwd: new URL('../../apps/desktop', import.meta.url).pathname,
  })
  console.log('\nShowcase images saved to website/docs/public/readme/showcase/')
} catch (error) {
  console.error(
    '\nShowcase generation failed. Make sure raw screenshots exist in website/docs/public/screenshots/',
  )
  process.exit(1)
}
